      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.status === 'success') {
            resolve({
              lat: json.lat,
              lon: json.lon,
              name: `${json.city}, ${json.regionName}`
            });
          } else {
            reject(new Error(json.message || 'Failed to get IP location'));
